        "heading": "Code Walkthrough",
        "content": "### Basic: Submit, Poll, Collect\n```python\nimport time\nfrom anthropic import Anthropic\n\nclient = Anthropic()\n\n# 1. BUILD REQUESTS\ndocuments = load_documents()  # Your data\nrequests = [\n    {\n        \"custom_id\": doc[\"id\"],\n        \"params\": {\n            \"model\": \"claude-haiku-4-5-20251001\",\n            \"max_tokens\": 512,\n            \"system\": \"Summarize this document in 2 sentences.\",\n            \"messages\": [{\"role\": \"user\", \"content\": doc[\"text\"]}]\n        }\n    }\n    for doc in documents\n]\n\n# 2. SUBMIT BATCH\nbatch = client.messages.batches.create(requests=requests)\nprint(f\"Submitted: {batch.id} ({len(requests)} requests)\")\n\n# 3. POLL UNTIL DONE\nwhile True:\n    status = client.messages.batches.retrieve(batch.id)\n    counts = status.request_counts\n    print(f\"  succeeded={counts.succeeded} processing={counts.processing} errored={counts.errored}\")\n    \n    if status.processing_status == \"ended\":\n        break\n    time.sleep(30)\n\n# 4. COLLECT RESULTS\nresults = {}\nfor entry in client.messages.batches.results(batch.id):\n    if entry.result.type == \"succeeded\":\n        results[entry.custom_id] = {\n            \"text\": entry.result.message.content[0].text,\n            \"input_tokens\": entry.result.message.usage.input_tokens,\n            \"output_tokens\": entry.result.message.usage.output_tokens,\n        }\n    elif entry.result.type == \"errored\":\n        results[entry.custom_id] = {\n            \"error\": f\"{entry.result.error.type}: {entry.result.error.message}\"\n        }\n\nprint(f\"Completed: {len(results)} results\")\n```\n\n### Advanced: Mixed-Model Batch with Retry\n```python\nfrom anthropic import Anthropic, RateLimitError\n\nclient = Anthropic()\n\ndef build_batch_requests(tasks: list[dict]) -> list[dict]:\n    \"\"\"Build batch with model routing per task.\"\"\"\n    requests = []\n    for task in tasks:\n        # Route by complexity\n        if task[\"type\"] in (\"classify\", \"extract\", \"tag\"):\n            model = \"claude-haiku-4-5-20251001\"\n        elif task[\"type\"] in (\"summarize\", \"generate\", \"review\"):\n            model = \"claude-sonnet-4-6-20250514\"\n        else:\n            model = \"claude-opus-4-6-20250514\"\n        \n        requests.append({\n            \"custom_id\": task[\"id\"],\n            \"params\": {\n                \"model\": model,\n                \"max_tokens\": task.get(\"max_tokens\", 1024),\n                \"messages\": [{\"role\": \"user\", \"content\": task[\"prompt\"]}]\n            }\n        })\n    return requests\n\ndef submit_with_retry(requests: list[dict], max_retries: int = 3) -> str:\n    \"\"\"Submit batch with exponential backoff on rate limits.\"\"\"\n    for attempt in range(max_retries):\n        try:\n            batch = client.messages.batches.create(requests=requests)\n            return batch.id\n        except RateLimitError as e:\n            wait = 2 ** attempt * 10\n            print(f\"Rate limited, waiting {wait}s...\")\n            time.sleep(wait)\n    raise Exception(\"Failed to submit batch after retries\")\n\ndef collect_and_retry_failures(batch_id: str, original_tasks: dict) -> dict:\n    \"\"\"Collect results, re-submit failures as individual requests.\"\"\"\n    results = {}\n    failures = []\n    \n    for entry in client.messages.batches.results(batch_id):\n        cid = entry.custom_id\n        if entry.result.type == \"succeeded\":\n            results[cid] = entry.result.message.content[0].text\n        elif entry.result.type == \"errored\":\n            failures.append(original_tasks[cid])\n    \n    # Retry failures individually (they may have had transient errors)\n    for task in failures:\n        try:\n            response = client.messages.create(**task[\"params\"])\n            results[task[\"id\"]] = response.content[0].text\n        except Exception as e:\n            results[task[\"id\"]] = f\"FAILED: {e}\"\n    \n    return results\n```\n\n### Async Pattern\n```python\nimport asyncio\nfrom anthropic import AsyncAnthropic\n\nasync def process_batch_async(requests: list[dict]) -> list:\n    client = AsyncAnthropic()\n    \n    batch = await client.messages.batches.create(requests=requests)\n    \n    while True:\n        status = await client.messages.batches.retrieve(batch.id)\n        if status.processing_status == \"ended\":\n            break\n        await asyncio.sleep(30)\n    \n    results = []\n    async for entry in await client.messages.batches.results(batch.id):\n        results.append(entry)\n    \n    return results\n```"
