        "content": "### Pattern 1: Static Router\n```python\nfrom anthropic import Anthropic\n\nHAIKU = \"claude-haiku-4-5-20251001\"\nSONNET = \"claude-sonnet-4-6-20250514\"\nOPUS = \"claude-opus-4-6-20250514\"\n\n# Map task types to models\nMODEL_ROUTING = {\n    # Haiku tier ŌĆö mechanical, deterministic\n    \"classify\": HAIKU, \"extract\": HAIKU, \"route\": HAIKU,\n    \"format\": HAIKU, \"tag\": HAIKU, \"validate\": HAIKU,\n    \"filter\": HAIKU, \"parse\": HAIKU,\n    \n    # Sonnet tier ŌĆö creative, analytical\n    \"generate\": SONNET, \"summarize\": SONNET, \"review\": SONNET,\n    \"analyze\": SONNET, \"explain\": SONNET, \"write\": SONNET,\n    \"test\": SONNET, \"refactor\": SONNET,\n    \n    # Opus tier ŌĆö complex reasoning\n    \"plan\": OPUS, \"architect\": OPUS, \"debug_complex\": OPUS,\n    \"design_prompt\": OPUS, \"research\": OPUS,\n}\n\ndef get_model(task_type: str) -> str:\n    return MODEL_ROUTING.get(task_type, SONNET)\n```\n\n### Pattern 2: Confidence-Based Cascade\n```python\ndef cascade_call(\n    client: Anthropic,\n    messages: list,\n    system: str,\n    confidence_check,  # Function that evaluates output quality\n    max_tokens: int = 1024,\n) -> dict:\n    \"\"\"Try cheapest model first, escalate if quality is insufficient.\"\"\"\n    \n    tiers = [\n        (HAIKU, \"haiku\"),\n        (SONNET, \"sonnet\"),\n        (OPUS, \"opus\"),\n    ]\n    \n    for model_id, tier_name in tiers:\n        response = client.messages.create(\n            model=model_id,\n            max_tokens=max_tokens,\n            system=system,\n            messages=messages,\n        )\n        \n        result = response.content[0].text\n        confidence = confidence_check(result)\n        \n        if confidence >= 0.8:  # Threshold ŌĆö tune per use case\n            return {\n                \"text\": result,\n                \"model_used\": tier_name,\n                \"confidence\": confidence,\n                \"usage\": response.usage,\n            }\n    \n    # Opus ceiling ŌĆö return regardless of confidence\n    return {\n        \"text\": result,\n        \"model_used\": \"opus\",\n        \"confidence\": confidence,\n        \"usage\": response.usage,\n    }\n```\n\n### Pattern 3: Haiku Classifier + Sonnet/Opus Router\n```python\ndef classify_then_route(client: Anthropic, user_input: str) -> str:\n    \"\"\"Use Haiku to classify complexity, then route to appropriate model.\"\"\"\n    \n    # Step 1: Haiku classifies the task (costs ~$0.0001)\n    classification = client.messages.create(\n        model=HAIKU,\n        max_tokens=50,\n        system=\"Classify this request as: simple, moderate, or complex. Reply with only the classification.\",\n        messages=[{\"role\": \"user\", \"content\": user_input}]\n    )\n    \n    complexity = classification.content[0].text.strip().lower()\n    \n    # Step 2: Route based on classification\n    model = {\n        \"simple\": HAIKU,\n        \"moderate\": SONNET,\n        \"complex\": OPUS,\n    }.get(complexity, SONNET)\n    \n    # Step 3: Execute with routed model\n    response = client.messages.create(\n        model=model,\n        max_tokens=2048,\n        messages=[{\"role\": \"user\", \"content\": user_input}]\n    )\n    \n    return response.content[0].text\n```\n\n### Pattern 4: Eval-Driven Model Selection\n```python\nimport json\n\ndef run_model_eval(\n    client: Anthropic,\n    test_cases: list[dict],  # [{\"prompt\": \"...\", \"expected\": \"...\", \"scorer\": callable}]\n    models: list[str] = [HAIKU, SONNET, OPUS],\n) -> dict:\n    \"\"\"Run same prompts across models, score quality, find cheapest acceptable.\"\"\"\n    \n    results = {model: {\"scores\": [], \"total_cost\": 0} for model in models}\n    \n    for test in test_cases:\n        for model in models:\n            response = client.messages.create(\n                model=model,\n                max_tokens=1024,\n                messages=[{\"role\": \"user\", \"content\": test[\"prompt\"]}]\n            )\n            \n            output = response.content[0].text\n            score = test[\"scorer\"](output, test[\"expected\"])\n            \n            results[model][\"scores\"].append(score)\n            results[model][\"total_cost\"] += calculate_cost(model, response.usage)\n    \n    # Report\n    for model in models:\n        scores = results[model][\"scores\"]\n        avg = sum(scores) / len(scores)\n        cost = results[model][\"total_cost\"]\n        print(f\"{model}: avg_score={avg:.2f}, cost=${cost:.4f}\")\n    \n    return results\n```"
